import{_ as r,c as e,o as i,ah as o}from"./chunks/framework.Cnj7lwEt.js";const p=JSON.parse('{"title":"项目名称","description":"","frontmatter":{},"headers":[],"relativePath":"github汇总/AI视频生成/EasyAnimate-AI视频生成.md","filePath":"github汇总/AI视频生成/EasyAnimate-AI视频生成.md"}'),t={name:"github汇总/AI视频生成/EasyAnimate-AI视频生成.md"};function l(n,a,s,h,c,d){return i(),e("div",null,a[0]||(a[0]=[o('<h1 id="项目名称" tabindex="-1">项目名称 <a class="header-anchor" href="#项目名称" aria-label="Permalink to “项目名称”">​</a></h1><p>EasyAnimate</p><h1 id="作者或组织名" tabindex="-1">作者或组织名 <a class="header-anchor" href="#作者或组织名" aria-label="Permalink to “作者或组织名”">​</a></h1><p>阿里巴巴PAI团队</p><h1 id="项目类别" tabindex="-1">项目类别 <a class="header-anchor" href="#项目类别" aria-label="Permalink to “项目类别”">​</a></h1><p>AI视频生成</p><h1 id="核心痛点" tabindex="-1">核心痛点 <a class="header-anchor" href="#核心痛点" aria-label="Permalink to “核心痛点”">​</a></h1><p>视频生成门槛高、专业设备要求高、生成效果不稳定、缺少易用工具</p><h1 id="主要功能" tabindex="-1">主要功能 <a class="header-anchor" href="#主要功能" aria-label="Permalink to “主要功能”">​</a></h1><ul><li>文本到视频生成</li><li>图像到视频生成</li><li>视频到视频生成</li><li>控制视频生成（Canny、Pose、Depth、轨迹控制、相机控制等）</li><li>支持多种分辨率（512、768、1024）</li><li>中英文双语预测</li><li>支持模型训练（VAE、DiT、Lora）</li></ul><h1 id="项目亮点" tabindex="-1">项目亮点 <a class="header-anchor" href="#项目亮点" aria-label="Permalink to “项目亮点”">​</a></h1><ul><li>阿里巴巴PAI团队开发，质量可靠</li><li>最新V5.1版本使用Qwen2 VL作为文本编码器</li><li>使用Flow作为采样方法</li><li>支持多种控制方式</li><li>中英文双语支持</li><li>已集成到Diffusers</li><li>支持多种GPU显存配置</li></ul><h1 id="荣誉信息" tabindex="-1">荣誉信息 <a class="header-anchor" href="#荣誉信息" aria-label="Permalink to “荣誉信息”">​</a></h1><p>README/仓库信息中未明确说明</p><h1 id="项目地址" tabindex="-1">项目地址 <a class="header-anchor" href="#项目地址" aria-label="Permalink to “项目地址”">​</a></h1><p><a href="https://github.com/aigc-apps/EasyAnimate" target="_blank" rel="noreferrer">https://github.com/aigc-apps/EasyAnimate</a> <a href="/网络环境.html">海外网络环境配置 →</a></p><h1 id="安装或部署教程" tabindex="-1">安装或部署教程 <a class="header-anchor" href="#安装或部署教程" aria-label="Permalink to “安装或部署教程”">​</a></h1><h2 id="教程适用对象与环境范围" tabindex="-1">教程适用对象与环境范围 <a class="header-anchor" href="#教程适用对象与环境范围" aria-label="Permalink to “教程适用对象与环境范围”">​</a></h2><p>适用于想要使用EasyAnimate进行视频生成的开发者，支持Windows和Linux，需要NVIDIA GPU。</p><h2 id="前置条件检查" tabindex="-1">前置条件检查 <a class="header-anchor" href="#前置条件检查" aria-label="Permalink to “前置条件检查”">​</a></h2><ol><li>系统要求：Windows 10或Linux（Ubuntu 20.04、CentOS）</li><li>Python版本：Python 3.10或3.11</li><li>PyTorch版本：torch 2.2.0</li><li>CUDA版本：11.8或12.1</li><li>CUDNN版本：8+</li><li>GPU要求：NVIDIA GPU，16GB显存起步，推荐24GB以上</li><li>磁盘空间：约60GB可用空间</li></ol><h2 id="主路径-docker安装-推荐" tabindex="-1">主路径：Docker安装（推荐） <a class="header-anchor" href="#主路径-docker安装-推荐" aria-label="Permalink to “主路径：Docker安装（推荐）”">​</a></h2><h3 id="步骤1-拉取docker镜像" tabindex="-1">步骤1：拉取Docker镜像 <a class="header-anchor" href="#步骤1-拉取docker镜像" aria-label="Permalink to “步骤1：拉取Docker镜像”">​</a></h3><p><strong>步骤目标</strong>：获取EasyAnimate的Docker镜像 <strong>执行位置</strong>：命令行终端 <strong>完整命令或操作</strong>：运行 <code>docker pull mybigpai-public-registry.cn-beijing.cr.aliyuncs.com/easycv/torch_cuda:easyanimate</code><strong>成功标志</strong>：镜像拉取完成 <strong>失败处理</strong>：检查Docker是否正常运行</p><h3 id="步骤2-启动docker容器" tabindex="-1">步骤2：启动Docker容器 <a class="header-anchor" href="#步骤2-启动docker容器" aria-label="Permalink to “步骤2：启动Docker容器”">​</a></h3><p><strong>步骤目标</strong>：启动EasyAnimate的Docker容器 <strong>执行位置</strong>：命令行终端 <strong>完整命令或操作</strong>：运行 <code>docker run -it -p 7860:7860 --network host --gpus all --security-opt seccomp:unconfined --shm-size 200g mybigpai-public-registry.cn-beijing.cr.aliyuncs.com/easycv/torch_cuda:easyanimate</code><strong>成功标志</strong>：容器启动成功并进入容器 <strong>失败处理</strong>：检查NVIDIA Docker是否安装</p><h3 id="步骤3-克隆代码" tabindex="-1">步骤3：克隆代码 <a class="header-anchor" href="#步骤3-克隆代码" aria-label="Permalink to “步骤3：克隆代码”">​</a></h3><p><strong>步骤目标</strong>：获取EasyAnimate代码 <strong>执行位置</strong>：Docker容器内 <strong>完整命令或操作</strong>：运行 <code>git clone https://github.com/aigc-apps/EasyAnimate.git &amp;&amp; cd EasyAnimate</code><strong>成功标志</strong>：代码克隆完成 <strong>失败处理</strong>：检查网络连接</p><h3 id="步骤4-下载模型权重" tabindex="-1">步骤4：下载模型权重 <a class="header-anchor" href="#步骤4-下载模型权重" aria-label="Permalink to “步骤4：下载模型权重”">​</a></h3><p><strong>步骤目标</strong>：获取预训练模型权重 <strong>执行位置</strong>：Docker容器内 <strong>完整命令或操作</strong>：创建models目录，从Hugging Face或ModelScope下载权重 <strong>成功标志</strong>：权重下载完成 <strong>失败处理</strong>：检查网络连接</p><h3 id="步骤5-运行推理" tabindex="-1">步骤5：运行推理 <a class="header-anchor" href="#步骤5-运行推理" aria-label="Permalink to “步骤5：运行推理”">​</a></h3><p><strong>步骤目标</strong>：开始使用EasyAnimate生成视频 <strong>执行位置</strong>：Docker容器内 <strong>完整命令或操作</strong>：运行Python脚本或启动Gradio WebUI <strong>成功标志</strong>：推理成功运行，生成视频 <strong>失败处理</strong>：检查显存是否足够</p><h2 id="安装成功验证" tabindex="-1">安装成功验证 <a class="header-anchor" href="#安装成功验证" aria-label="Permalink to “安装成功验证”">​</a></h2><p>运行推理命令，成功生成视频文件，或访问Gradio WebUI界面正常显示。</p><h2 id="常见错误排查" tabindex="-1">常见错误排查 <a class="header-anchor" href="#常见错误排查" aria-label="Permalink to “常见错误排查”">​</a></h2><ol><li><p><strong>现象</strong>：显存不足</p><ul><li><strong>可能原因</strong>：GPU显存不够</li><li><strong>解决步骤</strong>：使用model_cpu_offload或model_cpu_offload_and_qfloat8选项</li></ul></li><li><p><strong>现象</strong>：模型权重下载失败</p><ul><li><strong>可能原因</strong>：网络问题</li><li><strong>解决步骤</strong>：参考 <a href="/网络环境.html">海外网络环境配置 →</a>，或使用ModelScope镜像</li></ul></li><li><p><strong>现象</strong>：不支持bfloat16</p><ul><li><strong>可能原因</strong>：GPU不支持（如2080ti、V100）</li><li><strong>解决步骤</strong>：将weight_dtype改为torch.float16</li></ul></li></ol><h2 id="备选部署路径-本地安装" tabindex="-1">备选部署路径：本地安装 <a class="header-anchor" href="#备选部署路径-本地安装" aria-label="Permalink to “备选部署路径：本地安装”">​</a></h2><p>如Docker不适用，可参考README中的本地安装指南进行安装。</p><h2 id="信息缺失说明" tabindex="-1">信息缺失说明 <a class="header-anchor" href="#信息缺失说明" aria-label="Permalink to “信息缺失说明”">​</a></h2><p>README提供了较为完整的安装指引。</p>',40)]))}const m=r(t,[["render",l]]);export{p as __pageData,m as default};
